import{_ as t,o,c as s,a3 as i}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"13. Dispute Resolution Procedure","description":"","frontmatter":{"title":"13. Dispute Resolution Procedure","eba":"Nurses and Midwives 2024-2028","topics":["leave","parental-leave","disputes","flexible-work"]},"headers":[],"relativePath":"ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.md","filePath":"ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.md"}'),n={name:"ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.md"};function r(a,e,p,l,u,d){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="_13-dispute-resolution-procedure" tabindex="-1">13. Dispute Resolution Procedure <a class="header-anchor" href="#_13-dispute-resolution-procedure" aria-label="Permalink to &quot;13. Dispute Resolution Procedure&quot;">​</a></h1><p><strong>13.1</strong> Resolution of disputes and grievances</p><p><strong>(a)</strong> For the purpose of this clause 13, a dispute includes a grievance.</p><p><strong>(b)</strong> This dispute resolution procedure will apply to any dispute arising in relation to:</p><p><strong>(i)</strong> this Agreement (for the avoidance of doubt, this includes a request for flexible working arrangements or a request for an additional 12 months&#39; parental leave); or</p><p><strong>(ii)</strong> the NES.</p><p><strong>(c)</strong> A Party for the purposes of this clause is the Employee/s or the Employer that are subject to the dispute.</p><p><strong>(d)</strong> A Party subject to the dispute may choose to be represented at any stage by a representative including a Union or employer organisation. A representative, including a Union or employer organisation on behalf of an Employer, may initiate a dispute.</p><p><strong>13.2</strong> Obligations</p><p><strong>(a)</strong> The Parties to the dispute and their representatives must genuinely attempt to resolve the dispute through the processes set out in this clause and must cooperate to ensure that these processes are carried out expeditiously.</p><p><strong>(b)</strong> While the dispute resolution procedure is being conducted work will continue normally according to the usual practice that existed before the dispute, until the dispute is resolved.</p><p><strong>(c)</strong> This requirement does not apply where an Employee:</p><p><strong>(i)</strong> has a reasonable concern about an imminent risk to their health or safety;</p><p><strong>(ii)</strong> has advised the Employer of the concern; and</p><p><strong>(iii)</strong> has not unreasonably failed to comply with a direction by the Employer to perform other available work that is safe and appropriate for the Employee to perform.</p><p><strong>(d)</strong> No Party to a dispute or person covered by the Agreement will be prejudiced with respect to the resolution of the dispute by continuing work under this clause.</p><p><strong>13.3</strong> Dispute settlement facilitation</p><p><strong>(a)</strong> Where the chosen representative is another Employee of the Employer, that Employee will be released by the Employer from normal duties as is reasonably necessary to enable them to represent the Employee/s including:</p><p><strong>(i)</strong> investigating the circumstances of the dispute; and</p><p><strong>(ii)</strong> participating in the processes to resolve the dispute, including conciliation and arbitration.</p><p><strong>(b)</strong> An Employee who is a Party to the dispute will be released by the Employer from normal duties as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Employer.</p><p><strong>13.4</strong> Discussion of dispute at workplace</p><p><strong>(a)</strong> The Parties will attempt to resolve the dispute at the workplace as follows:</p><p><strong>(i)</strong> in the first instance by discussions between the Employee/s and the Employee&#39;s line manager or other relevant manager; and</p><p><strong>(ii)</strong> if the dispute is still unresolved, by discussions between the Employee/s and more senior managers.</p><p>Nothing in this clause 13.4 prevents the Parties from agreeing, at any time, to conducting their discussions in writing, subject to clause 13.2.</p><p><strong>(b)</strong> The discussions at subclause 13.4(a) will take place within fourteen days or such longer period as mutually agreed, save that agreement will not be unreasonably withheld.</p><p><strong>(c)</strong> Where a Party believes the requirements of this clause 13.4 have not been complied with, they will notify the other of their concern in writing as soon as practicable.</p><p><strong>(d)</strong> If a dispute cannot be resolved at the workplace it may be referred by a Party to the dispute or representative to the Commission for conciliation and, if the matter in dispute remains unresolved, arbitration.</p><p><strong>13.5</strong> Disputes of a collective character</p><p>Disputes of a collective character may be dealt with more expeditiously by an early reference to the Commission. However, no dispute of a collective character may be referred to the Commission directly without a genuine attempt to resolve the dispute at the workplace level.</p><p><strong>13.6</strong> Conciliation</p><p><strong>(a)</strong> Where a dispute is referred for conciliation, the Commission member will do everything the member deems right and proper to assist the Parties to settle the dispute.</p><p><strong>(b)</strong> Conciliation before the Commission is complete when:</p><p><strong>(i)</strong> the Parties to the dispute agree that it is settled; or</p><p><strong>(ii)</strong> the Commission member conducting the conciliation, either on their own motion or after an application by a Party, is satisfied there is no likelihood that further conciliation will result in settlement within a reasonable period; or</p><p><strong>(iii)</strong> the Parties to the dispute inform the Commission member there is no likelihood the dispute will be settled and the member does not have substantial reason to refuse to regard conciliation as complete.</p><p><strong>13.7</strong> Arbitration</p><p><strong>(a)</strong> If, when conciliation is complete, the dispute is not settled, either Party may request the Commission proceed to determine the dispute by arbitration.</p><p><strong>(b)</strong> The Commission member that conciliated the dispute will not arbitrate the dispute if a Party objects to the member doing so.</p><p><strong>(c)</strong> Subject to subclause 13.7(d) below, a decision of the Commission is binding upon the persons covered by this Agreement.</p><p><strong>(d)</strong> An appeal lies to a Full Bench of the Commission, with the leave of the Full Bench, against a determination of a single member of the Commission made pursuant to this clause.</p><p><strong>13.8</strong> Conduct of matters before the Commission</p><p><strong>(a)</strong> Subject to any agreement between the Parties to the dispute in relation to a particular dispute or grievance and the provisions of this clause, in dealing with a dispute or grievance through conciliation or arbitration, the Commission will conduct the matter in accordance with sections 577, 578 and Subdivision B of Division 3 of Part 5-1 of the Act.</p><p><strong>(b)</strong> For the avoidance of doubt, nothing in this clause 13 affects the operation of section 596 of the Act.</p><p><strong>13.9</strong> Interaction with Statewide Industry Panel</p><p><strong>(a)</strong> In respect to any matter arising under <a href="/eba/ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.html">clauses 14.3</a> and 11B, disputes will only be resolved by the Statewide Industry Panel in accordance with the terms of <a href="/eba/ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.html">clause 14</a>.</p><p><strong>(b)</strong> Where an application is made under <a href="/eba/ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.html">clause 14.4</a> (concerning an existing classification), the dispute resolution procedure may also be used by either Party except that arbitration under clause 13.7 may only occur by agreement between the Parties.</p><p><strong>(c)</strong> Determinations of the Statewide Industry Panel under <a href="/eba/ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.html">clause 14.8</a> will, subject to subclauses 14.6(e) to 14.6(i), be binding on the Employers and the Employees.</p><p>Plain language terms: dispute, grievance, dispute process, FWC dispute.</p>',50)])])}const g=t(n,[["render",r]]);export{c as __pageData,g as default};
